"use client";

import { useState, useRef, useEffect } from "react";
import styles from "./AIChat.module.css";
import type { ChatMessageData } from "@/types";

export default function AIChat() {
    const [messages, setMessages] = useState<ChatMessageData[]>([]);
    const [input, setInput] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    // Initial load history
    useEffect(() => {
        fetch("/api/chat/history")
            .then(res => res.json())
            .then(data => {
                if (data.success && data.data && data.data.length > 0) {
                    setMessages(data.data.map((m: any) => ({
                        role: m.role,
                        content: m.content
                    })));
                } else {
                    // Default greeting
                    setMessages([{
                        role: "assistant",
                        content: "Hello! I am your CS2 Market Agent.\nAsk me about your portfolio, market movers, or item prices."
                    }]);
                }
            })
            .catch(err => console.error("Failed to load history", err));
    }, []);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const handleSubmit = async (e?: React.FormEvent) => {
        e?.preventDefault();
        if (!input.trim() || isLoading) return;

        const userMsg = { role: "user" as const, content: input.trim() };
        setMessages(prev => [...prev, userMsg]);
        setInput("");
        setIsLoading(true);

        // Placeholder for assistant message while streaming
        setMessages(prev => [...prev, { role: "assistant", content: "" }]);

        try {
            const res = await fetch("/api/chat", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ messages: [...messages, userMsg] }) // Send full context history
            });

            if (!res.ok) throw new Error("API Error");
            if (!res.body) throw new Error("No response body");

            const reader = res.body.getReader();
            const decoder = new TextDecoder("utf-8");

            while (true) {
                const { done, value } = await reader.read();
                if (done) break;

                const chunk = decoder.decode(value, { stream: true });
                setMessages(prev => {
                    const next = [...prev];
                    const lastIndex = next.length - 1;
                    const lastMsg = next[lastIndex];
                    if (lastMsg.role === "assistant") {
                        next[lastIndex] = { ...lastMsg, content: lastMsg.content + chunk };
                    }
                    return next;
                });
            }
        } catch (error) {
            console.error("Chat error:", error);
            setMessages(prev => {
                const next = [...prev];
                const lastIndex = next.length - 1;
                next[lastIndex] = { role: "assistant", content: "Sorry, I encountered an error while processing your request. Please ensure you have set GEMINI_API_KEY or OPENAI_API_KEY in your .env.local file, and that your database is reachable." };
                return next;
            });
        } finally {
            setIsLoading(false);
        }
    };

    // Helper to format basic markdown
    const formatMessage = (content: string) => {
        return content.split('\n').map((line, i) => {
            // Naive bold parsing logic
            const formattedLine = line.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
            return (
                <span key={i}>
                    <span dangerouslySetInnerHTML={{ __html: formattedLine }} />
                    <br />
                </span>
            );
        });
    };

    return (
        <div className={styles.container}>
            <div className={styles.header}>
                <div className={styles.headerIcon}>≡ƒñû</div>
                <div>
                    <div className={styles.headerTitle}>CS2Vault AI Agent</div>
                    <div className={styles.headerSub}>Powered by Gemini & OpenAI Fast Fallback</div>
                </div>
            </div>

            <div className={styles.messages}>
                {messages.map((msg, idx) => (
                    <div
                        key={idx}
                        className={`${styles.message} ${msg.role === 'user' ? styles.messageUser : styles.messageAssistant}`}
                    >
                        {formatMessage(msg.content)}
                    </div>
                ))}

                {isLoading && messages[messages.length - 1]?.content === "" && (
                    <div className={styles.messageLoading}>
                        <div className={styles.dot}></div>
                        <div className={styles.dot}></div>
                        <div className={styles.dot}></div>
                        <span style={{ marginLeft: "8px" }}>Fetching market context...</span>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            <form className={styles.inputArea} onSubmit={handleSubmit}>
                <input
                    type="text"
                    className={styles.input}
                    placeholder="Ask about your portfolio or live market data..."
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    disabled={isLoading}
                />
                <button
                    type="submit"
                    className={styles.sendBtn}
                    disabled={!input.trim() || isLoading}
                >
                    Γ₧ñ
                </button>
            </form>
        </div>
    );
}

