/**
 * CSFloat Market Data Provider
 *
 * Endpoints:
 *   - /api/v1/listings ΓÇö active market listings (with item SCM prices)
 *   - /api/v1/history/{item}/sales ΓÇö recent sales (40 most recent)
 *
 * Auth: API key via Authorization header
 * Prices are returned in USD cents.
 * Rate limits: per-endpoint, not publicly documented ΓÇö we use conservative 1 req/2s.
 */

import type { MarketDataProvider, PriceData, PricePoint, RateLimitConfig } from "@/types";
import { csfloatQueue } from "@/lib/api-queue";

const BASE_URL = "https://csfloat.com/api/v1";

function getApiKey(): string {
    const key = process.env.CSFLOAT_API_KEY;
    if (!key) throw new Error("CSFLOAT_API_KEY is not configured");
    return key;
}

function makeHeaders(): HeadersInit {
    return {
        Authorization: getApiKey(),
        "Content-Type": "application/json",
    };
}

interface CSFloatListing {
    id: string;
    price: number; // cents
    item: {
        market_hash_name: string;
        float_value: number;
        paint_seed: number;
        icon_url: string;
        scm?: {
            price: number;  // Steam Community Market price in cents
            volume: number;
        };
        item_name: string;
        wear_name: string;
    };
}

export const csfloatProvider: MarketDataProvider = {
    name: "csfloat",

    async fetchItemPrice(marketHashName: string): Promise<PriceData> {
        const listings = await csfloatQueue.enqueue(async () => {
            const url = new URL(`${BASE_URL}/listings`);
            url.searchParams.set("market_hash_name", marketHashName);
            url.searchParams.set("sort_by", "lowest_price");
            url.searchParams.set("limit", "5");

            const res = await fetch(url.toString(), { headers: makeHeaders() });
            if (!res.ok) {
                throw new Error(`CSFloat API error: ${res.status} ${res.statusText}`);
            }
            return res.json() as Promise<CSFloatListing[]>;
        });

        if (!listings || listings.length === 0) {
            throw new Error(`No CSFloat listings found for "${marketHashName}"`);
        }

        // Use the lowest listing price as the current price
        const lowest = listings[0];
        const priceUsd = lowest.price / 100;

        return {
            price: priceUsd,
            volume: lowest.item.scm?.volume ?? undefined,
            source: "csfloat",
            timestamp: new Date(),
        };
    },

    async fetchBulkPrices(items: string[]): Promise<Map<string, PriceData>> {
        const result = new Map<string, PriceData>();

        // CSFloat doesn't have a dedicated bulk endpoint.
        // We fetch listings for each item individually through the queue.
        for (const marketHashName of items) {
            try {
                const priceData = await csfloatProvider.fetchItemPrice(marketHashName);
                result.set(marketHashName, priceData);
            } catch (error) {
                console.warn(
                    `[CSFloat] Failed to fetch price for "${marketHashName}":`,
                    error instanceof Error ? error.message : error
                );
            }
        }

        return result;
    },

    async fetchItemHistory(marketHashName: string, _days: number): Promise<PricePoint[]> {
        // CSFloat provides recent sales via the history endpoint
        const sales = await csfloatQueue.enqueue(async () => {
            const encoded = encodeURIComponent(marketHashName);
            const url = `${BASE_URL}/history/${encoded}/sales`;

            const res = await fetch(url, { headers: makeHeaders() });
            if (!res.ok) {
                if (res.status === 404) return [];
                throw new Error(`CSFloat history error: ${res.status} ${res.statusText}`);
            }
            return res.json();
        });

        if (!Array.isArray(sales)) return [];

        return sales.map((sale: { sold_at: string; price: number }) => ({
            price: sale.price / 100,
            timestamp: new Date(sale.sold_at),
        }));
    },

    getRateLimitConfig(): RateLimitConfig {
        return {
            maxRequestsPerMinute: 30,
            maxRequestsPerDay: 5000,
            minDelayMs: 2000,
        };
    },
};

/**
 * Steam Community Market Data Provider (Fallback)
 *
 * Endpoints:
 *   - /market/priceoverview ΓÇö single item price + volume
 *   - /ISteamEconomy/GetAssetPrices/v1 ΓÇö asset prices by appid
 *
 * Auth: No API key needed for price overview (public endpoint).
 * Rate limits: ~20 req/min (aggressive, use as fallback only).
 * Prices returned as formatted strings ("$12.34") ΓÇö parsed to float.
 */

import type { MarketDataProvider, PriceData, PricePoint, RateLimitConfig } from "@/types";
import { steamQueue } from "@/lib/api-queue";

const MARKET_BASE = "https://steamcommunity.com/market";
const CS2_APP_ID = "730";

/**
 * Parse Steam's "$12.34" price format to a number.
 */
export function parseSteamPrice(priceStr: string): number {
    // Remove currency symbols and whitespace
    let cleaned = priceStr.replace(/[^0-9.,]/g, "");

    // Handle thousands separators vs decimal commas:
    // If there's both commas and dots (e.g. "1,234.56"), commas are thousands separators
    // If there's only a comma (e.g. "12,34"), it's a decimal separator (European format)
    if (cleaned.includes(",") && cleaned.includes(".")) {
        // Has both: commas are thousands separators, dot is decimal
        cleaned = cleaned.replace(/,/g, "");
    } else if (cleaned.includes(",")) {
        // Only comma: treat as decimal separator
        cleaned = cleaned.replace(",", ".");
    }

    const parsed = parseFloat(cleaned);
    return isNaN(parsed) ? 0 : parsed;
}

export const steamProvider: MarketDataProvider = {
    name: "steam",

    async fetchItemPrice(marketHashName: string): Promise<PriceData> {
        const data = await steamQueue.enqueue(async () => {
            const url = new URL(`${MARKET_BASE}/priceoverview/`);
            url.searchParams.set("appid", CS2_APP_ID);
            url.searchParams.set("currency", "1"); // USD
            url.searchParams.set("market_hash_name", marketHashName);

            const res = await fetch(url.toString());
            if (!res.ok) {
                throw new Error(`Steam Market API error: ${res.status} ${res.statusText}`);
            }
            return res.json();
        });

        if (!data?.success) {
            throw new Error(`Steam Market returned no data for "${marketHashName}"`);
        }

        const price = parseSteamPrice(data.lowest_price ?? data.median_price ?? "$0");
        const medianPrice = parseSteamPrice(data.median_price ?? "$0");

        return {
            price: price || medianPrice,
            volume: data.volume ? parseInt(data.volume.replace(/,/g, ""), 10) : undefined,
            source: "steam",
            timestamp: new Date(),
        };
    },

    async fetchBulkPrices(items: string[]): Promise<Map<string, PriceData>> {
        const result = new Map<string, PriceData>();

        // Steam has no bulk endpoint ΓÇö must fetch one at a time.
        // Very slow due to aggressive rate limiting (1 req per 3s).
        for (const marketHashName of items) {
            try {
                const priceData = await steamProvider.fetchItemPrice(marketHashName);
                result.set(marketHashName, priceData);
            } catch (error) {
                console.warn(
                    `[Steam] Failed to fetch price for "${marketHashName}":`,
                    error instanceof Error ? error.message : error
                );
            }
        }

        return result;
    },

    async fetchItemHistory(_marketHashName: string, _days: number): Promise<PricePoint[]> {
        // Steam Market doesn't expose a public price history API.
        // The price history chart data on Steam's website is loaded via
        // an authenticated endpoint that requires login cookies.
        // We rely on local snapshot accumulation instead.
        console.warn("[Steam] Price history not available via public API. Using local snapshots.");
        return [];
    },

    getRateLimitConfig(): RateLimitConfig {
        return {
            maxRequestsPerMinute: 20,
            maxRequestsPerDay: 500,
            minDelayMs: 3000,
        };
    },
};
